chat_template:
{%- set ns = namespace(is_first_tool=true) %}
{%- set ns2 = namespace(last_user_index=-1) %}
{%- if not tools is defined %}
    {%- set tools = none %}
{%- endif %}
{%- if not thinking is defined %}
    {%- set thinking = true %}
{%- endif %}
{%- if not context_thinking is defined %}
    {%- set context_thinking = "Interleave" %}
{%- endif %}
{%- if context_thinking != "Preserve" and context_thinking != "DropAll" %}
    {%- set context_thinking = "Interleave" %}
{%- endif %}
{%- if not add_generation_prompt is defined %}
    {%- set add_generation_prompt = true %}
{%- endif %}

{#- content处理 #}
{%- macro render_content(content) %}
    {%- if content is string %}
        {{- content }}
    {%- elif content is iterable and content is not mapping %}
        {%- for item in content %}
            {%- if 'text' in item %}
                {{- item.text }}
            {%- elif item is string %}
                {{- item }}
            {%- endif %}
        {%- endfor %}
    {%- else %}
        {{- content }}
    {%- endif %}
{%- endmacro %}

{{- '<|pangu_text_start|><|message_start|>system\n' -}}
{#- 提取系统消息 #}
{%- set system_message = "" %}
{%- if messages[0]['role'] == 'system' %}
    {%- set system_message = render_content(messages[0]['content'] | default('', true)) |trim %}
    {%- set messages = messages[1:] %}
{%- endif %}
{#- 调用工具时的默认人设 #}
{%- if tools %}
    {%- if system_message %}
        {%- set system_message = system_message + "\n" %}
    {%- endif %}
    {%- set system_message = system_message + "你是一个能够调用外部工具解决问题的专家，你的目标是高效、准确、清晰地完成任务。\n你需要根据用户的问题，决定是否需要使用工具来完成任务。如果需要，请以明确的格式调用工具；如果不需要，请直接回答。\n你可以根据上下文决定是否继续调用工具或基于已有结果直接回答用户。如果工具调用已足够，请合理组织语言向用户汇报结论。在没有获得显式的调用结果之前，在调用工具的当轮回复之内严禁虚构或者假设一个工具调用结果来完成任务或者回答问题。也不应在没有返回工具调用信息的情况下，在调用工具的当轮假设或者明确声称工具执行成功。" %}
{%- endif %}
{{- system_message -}}
{#- 工具使用描述和规范调用格式 #}
{%- if tools %}
    {{- '\n你将在<tools></tools>标签对内获得每个工具的描述：\n<tools>\n' }}
    {{- tools | tojson(ensure_ascii=False, sort_keys=False) }}
    {{- '\n</tools>\n' }}
    {{- "对于每个函数调用，返回一个 JSON 对象，放在 <|tool_call_start|><|tool_call_end|> 标签对中，多个调用组成一个列表，其中每个函数包含函数名和对应函数的参数，格式如下：\n" }}
    {{- '<|tool_call_start|>\n[{"name": "<函数名1>", "arguments": <args1 json对象>}, {"name": "<函数名2>", "arguments": <args2 json对象>}, ...]\n<|tool_call_end|>' }}
    {{- '\n<工具使用原则>\n1. 只有在所有必填参数(required字段中列出的)都具备有效值时，才能调用该函数\n2. 如果缺少任何必填参数，必须向用户询问缺失的参数，而不是直接调用函数\n3. 可选参数如果没有提供可以忽略或使用默认值\n</工具使用原则>' }}
{%- endif %}
{{- '<|message_end|>' -}}

{#- 找最后一轮user的位置 #}
{%- for m in messages %}
    {%- if m.role == 'user' %}
        {%- set ns2.last_user_index = loop.index0 -%}
    {%- endif %}
{%- endfor %}

{#- messages的拼接 #}
{%- for message in messages %}
    {#- user轮次 #}
    {%- if message['role'] == 'user' %}
        {{- '<|message_start|>user\n' + render_content(message['content'] | default('', true)) -}}
        {%- if message.get('tool_calls') %}
            {{- '<|tool_call_start|>\n[' }}
            {%- set function_list = message.tool_calls | selectattr('function') | map(attribute='function') | list %}
            {%- for function_item in function_list %}
                {%- if not ns.is_first_tool %}
                    {{- ', ' -}}
                {%- endif %}
                {%- if function_item.arguments is string %}
                    {{- '{"name": "' + function_item.name + '", "arguments": ' + function_item.arguments + '}' -}}
                {%- else %}
                    {{- '{"name": "' + function_item.name + '", "arguments": ' + function_item.arguments | tojson(ensure_ascii=False, sort_keys=False) + '}' -}}
                {%- endif %}
                {%- set ns.is_first_tool = false %}
            {%- endfor %}
            {%- set ns.is_first_tool = true %}
            {{- ']\n<|tool_call_end|>' }}
        {%- endif %}
        {{- '<|message_end|>' -}}
    {%- endif %}

    {#- tool轮次 #}
    {%- if message['role'] == 'tool' %}
        {{- '<|message_start|>tool\n' + render_content(message['content'] | default('', true)) -}}
        {{- '<|message_end|>' -}}
    {%- endif %}

    {#- assistant轮次 #}
    {%- if message['role'] == 'assistant' %}
        {%- if 'reasoning_content' in message and message['reasoning_content'] %}
            {%- if thinking and context_thinking == "Preserve" %}
                {{- '<|message_start|>assistant\n<think>' + message['reasoning_content'] +'</think>' -}}
            {%- elif thinking and context_thinking == "Interleave" and loop.index0 > ns2.last_user_index %}
                {{- '<|message_start|>assistant\n<think>' + message['reasoning_content'] +'</think>' -}}
            {%- else %}
                {{- '<|message_start|>assistant\n</think>' -}}
            {%- endif %}
        {%- else %}
            {{- '<|message_start|>assistant\n</think>' -}}
        {%- endif %}
        {{- render_content(message['content'] | default('', true)) -}}
        {%- if message.get('tool_calls') %}
            {{- '<|tool_call_start|>\n[' }}
            {%- set function_list = message.tool_calls | selectattr('function') | map(attribute='function') | list %}
            {%- for function_item in function_list %}
                {%- if not ns.is_first_tool %}
                    {{- ', ' -}}
                {%- endif %}
                {%- if function_item.arguments is string %}
                    {{- '{"name": "' + function_item.name + '", "arguments": ' + function_item.arguments + '}' -}}
                {%- else %}
                    {{- '{"name": "' + function_item.name + '", "arguments": ' + function_item.arguments | tojson(ensure_ascii=False, sort_keys=False) + '}' -}}
                {%- endif %}
                {%- set ns.is_first_tool = false %}
            {%- endfor %}
            {%- set ns.is_first_tool = true %}
            {{- ']\n<|tool_call_end|>' }}
        {%- endif %}
        {{- '<|message_end|>' }}
    {%- endif %}
{%- endfor %}

{#- 最后的assistant轮 #}
{%- if add_generation_prompt %}
    {%- if thinking %}
        {{- '<|message_start|>assistant\n<think>' -}}
    {%- else %}
        {{- '<|message_start|>assistant\n</think>' -}}
    {%- endif %}
{%- endif %}
